INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('colonel-d0d1b9a2-moex-00098', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-110-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司12月31日公司帳上之存款餘額為$900,000。12月份之銀行對帳單 顯示12月份因存款不足而被退票為$30,000，其中$18,000又於12月底前 存入。12月底在途存款為$150,000，未兌現支票為 $144,000（包括$30,000 之支票銀行於12月20日保付）。12月16日公司誤將兌付他公司之支票 $19,800以$28,800記入公司帳上，公司尚未發現此項錯誤。12月份銀行代 收票據$60,000，並扣除代收手續費$300。試問甲公司12月31日之正確存 款餘額為何？', '["$906,000", "$938,700", "$956,700", "$986,700"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00099', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-110-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司X1 年初向乙公司承租一項特殊設備，租期5 年，租金於每年年初 支付。X5年底甲公司此項租賃相關項目餘額如下： 資產： 使用權資產 $900,000 累計折舊－使用權資產 900,000 負債： 租賃負債 $ 90,000 則關於該租賃，下列敘述何者最為可能：', '["甲公司將於X6年初以$90,000購買該設備", "該設備在X5年底的殘值為$90,000", "甲公司保證該設備在X5年底的殘值為$90,000", "該設備在X5年底的殘值較甲公司的保證金額少$90,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00100', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-110-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '乙公司 X5 年在現金流量表部分資料如下：特別股轉換成普通股$280,000 ，發放股票股利$450,000，購買設備付款$850,000，開立一張抵押票據購買 土地$2,500,000，出售按攤銷後成本衡量之投資得款$500,000，營業活動之 淨現金流入$1,500,000。乙公司X5年度之淨現金流量為何？', '["淨現金流入$650,000", "淨現金流入$1,150,000", "淨現金流出$350,000", "淨現金流出$1,000,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00101', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-110-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X3年1月2日購買乙公司所發行的可轉換公司債作為投資，X6 年底甲公司帳上公司債之公允價值為$108,000。若甲公司於 X7 年 3 月 1 日將公司債全部轉換為普通股 4,000 股，乙公司當日普通股每股公允價值 為$30（每股面額為$10），則前述交易對甲公司 X7 年損益影響數為何？ （不考慮所得稅影響數）', '["$0", "利益$12,000", "損失$28,000", "損失$68,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00102', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-110-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司在 X1 年 4 月 1 日取得一部設備，成本$580,000，估計耐用年限 5 年，殘值$40,000，後續衡量採成本模式。該設備原係以年數合計法提列折 舊，直至X3年初，甲公司決定改採直線法提列折舊。若所得稅率為20% ，改變折舊方法對X3年本期淨利之淨影響為何？（答案四捨五入至元）', '["本期淨利增加$7,200", "本期淨利增加$31,570", "本期淨利增加$31,466", "本期淨利增加$39,462"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00103', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-110-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '乙銀行於Xl年1月1日發行面額$1,000,000之債券，票面附息4%，三年 到期，每年12月31日付息，按$972,768價格發行。若乙銀行將發行債券 所得款項放款給甲客戶，利率 6%，三年到期，每年 12 月 31 日付息，合 約規定借款人（甲客戶）可隨時購買乙銀行發行之前述債券提前償還該借 款。乙銀行將該放款分類為透過損益按公允價值衡量之金融資產，同時也 將所發行之債券指定為透過損益按公允價值衡量。X1 年 1 月 1 日乙銀行 所發行債券之有效利率為 5%，此時指標利率為 4%。X1 年 12 月31 日該 債券之公允價值為$928,669，有效利率為 8%，指標利率為 6%。則 X1 年 度與該指定透過損益按公允價值衡量金融負債相關之其他綜合損益為多 少？（不考慮所得稅之影響，四捨五入取至元）', '["$0", "$17,090", "$44,099", "$52,737"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00104', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-110-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '假設公允價值能可靠衡量，下列資產項目中有幾項在原始認列時應以成本', '["生產性動物", "生產性植物", "後續衡量採公允價值模式衡量 之投資性不動產", "後續衡量採成本模式衡量之投資性不動產  ⑤由自 己農場收成供銷售之蘋果  ⑥由他人農場購入供銷售之蘋果"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00105', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-110-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', 'X1年8月1日甲公司與乙公司簽訂不可取消購貨合約，甲公司須於X4年', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00106', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-110-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '月 1 日前以每單位$20，向乙公司進貨 10,000 單位。另外，甲公司可於 到期前任何時點取消該合約，唯須支付罰金$50,000。甲公司會計期間採曆 年制，並評估X1年底、X2年底及X3年底該商品每單位之售價分別為$18 、$14及$16，試問，甲公司X3年度因上述合約應認列多少相關損益？', '["損失$20,000", "損失$40,000", "利益$10,000", "利益$20,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00107', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-110-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司在X1 年1月1 日購買一棟商業大樓，規劃將之出租以收取租金。 該棟大樓之總成本為$10,000,000，估計土地與建築物之公允價值分別為 $6,000,000與$4,000,000。甲公司於X1年3月1日以營業租賃方式出租予 乙公司，每月租金$20,000。預估該棟大樓之使用年限為25年，殘值$200,000 。X1 年底，土地與建築物之公允價值分別為$6,900,000 及$3,800,000。若 甲公司採公允價值模式衡量投資性不動產，甲公司 X1 年綜合損益表應表 達之相關損益共計多少？', '["利益$40,000", "利益$48,000", "利益$748,000", "利益$900,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL)
